node.toInstall:
@nestjs/jwt: ^10.2.0 (JWT token generation and validation)
@nestjs/passport: ^10.0.3 (Passport.js integration for NestJS)
passport: ^0.7.0 (Authentication middleware base)
passport-jwt: ^4.0.1 (JWT strategy for Passport)

interface.signature:
export const CurrentUser = createParamDecorator(
  (data: unknown, ctx: ExecutionContext): JwtPayload => {
    const request = ctx.switchToHttp().getRequest();
    return request.user;
  },
);

ideas.test:
Integration test request.user population:
- After successful JWT validation, verify request.user contains { sub, phoneNumber, domainID, roles }
- Verify @CurrentUser() decorator extracts correct payload
